#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(b,c) for(int c=head[(b)];c;c=nxt[c])
#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=4e5+10,M=2e6+10;
char ch[N];
struct Trie1
{
	int head[N],des[M],nxt[M],tot[N],cnt,gnt;char val[N];
	inline void Init(){memset(head,0,sizeof(head));memset(val,0,sizeof(val));memset(tot,0,sizeof(tot));gnt=0;cnt=1;}
	inline void add(int x,int y){des[++gnt]=y;nxt[gnt]=head[x];head[x]=gnt;};
	inline int Node(char q){val[++cnt]=q;return cnt;}
	void ins(char *ch,int i,int u=1)
	{
		int len=strlen(ch+1);if(i==len)return;
		grep(u,p){int v=des[p];if(val[v]==ch[i+1]){ins(ch,i+1,v);return;}}
		int v=Node(ch[i+1]);if(i)tot[ch[i+1]-'a']++;add(u,v);ins(ch,i+1,v);
	}
	char stk[N];int top;void debug(int cur)
	{
		stk[++top]=val[cur];if(tot[cur]){rep(1,top,i)putchar(stk[i]);puts("");}
		grep(cur,p)debug(des[p]);top--;return;
	}
}pre;
struct Trie2
{
	int head[N],des[M],nxt[M],tot[N],cnt,gnt;char val[N];
	inline void Init(){memset(head,0,sizeof(head));memset(val,0,sizeof(val));memset(tot,0,sizeof(tot));gnt=0;cnt=1;}
	inline void add(int x,int y){des[++gnt]=y;nxt[gnt]=head[x];head[x]=gnt;};
	inline int Node(char q){val[++cnt]=q;return cnt;}
	void ins(char *ch,int i,int u=1)
	{
//		printf("%d\n",u);
		int len=strlen(ch+1);if(i==1)return;
		grep(u,p){int v=des[p];if(val[v]==ch[i-1]){ins(ch,i-1,v);return;}}
		
		int v=Node(ch[i-1]);if(i<=len)tot[ch[i-1]-'a']++;add(u,v);ins(ch,i-1,v);
	}
	char stk[N];int top;void debug(int cur)
	{
		stk[++top]=val[cur];if(tot[cur]){rep(1,top,i)putchar(stk[i]);puts("");}
		grep(cur,p)debug(des[p]);top--;return;
	}
}suc;
int v[N];
signed main()
{
//	freopen("dictionary.in","r",stdin);
//	freopen("dictionary.out","w",stdout);
	int n;while(cin>>n)
	{
		memset(v,0,sizeof(v));
		pre.Init();suc.Init();
		pre.cnt=suc.cnt=1;while(n--)
		{
			scanf("%s",ch+1);int len=strlen(ch+1);
			if(len==1)v[ch[1]-'a']=1;
			pre.ins(ch,0);suc.ins(ch,len+1);
		}
	//	putchar(suc.val[5]);puts("");
		long long ans=1ll*(pre.cnt-1)*(suc.cnt-1);
	//	rep(0,25,i)printf("%d ",pre.tot[i]);puts("");
	//	rep(0,25,i)printf("%d ",suc.tot[i]);puts("");
		rep(0,25,i)ans-=1ll*pre.tot[i]*suc.tot[i],ans+=v[i];
		printf("%lld\n",ans);
	}
	
}
